{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem is an interactive optimization task involving spatial search and pattern matching. I will delegate the design of a search strategy and the implementation of the noise-resilient pattern matching logic.",
  "helpers": [
    {
      "label": "search_strategy_designer",
      "instructions": "Design an efficient probing strategy to locate hidden polyominoes on a grid. The strategy must balance the cost of single-cell queries (q 1) versus multi-cell aggregate queries (q k) to minimize total cost while maximizing information gain about the presence of shapes. Propose a sequence of queries that uses aggregate queries to narrow down candidate regions before using single-cell queries for precision."
    },
    {
      "label": "pattern_matching_logic",
      "instructions": "Develop a mathematical approach to identify specific polyomino shapes from noisy aggregate query results. Given a set of known polyomino shapes and noisy counts from multi-cell queries, create a method to calculate the probability or likelihood that a specific shape exists at a given coordinate. The method should handle the noise parameter provided in the input to distinguish between true oil cells and noise."
    }
  ],
  "synthesis_brief": "Combine the search strategy to determine the order and type of queries (single vs aggregate) with the pattern matching logic to interpret the results. The final solution should use the search strategy to probe the grid and the pattern matching logic to confirm the coordinates of the oil cells, finally outputting the result using the 'a' command."
}

